/**
 * @param {number[]} digitSum
 * @return {number}
 */
function solve(digitSum) {
    const MOD = 1000000007n;
    const MAX_VAL = 5000;

    /**
     * Calculates the sum of digits of a number.
     * @param {number} n
     * @returns {number}
     */
    const getDigitSum = (n) => {
        let sum = 0;
        let str = String(n);
        for (let i = 0; i < str.length; i++) {
            sum += parseInt(str[i]);
        }
        return sum;
    };

    /**
     * Finds all numbers <= MAX_VAL whose digit sum equals targetSum.
     * @param {number} targetSum
     * @returns {number[]} Sorted array of numbers.
     */
    const findNumbersByDigitSum = (targetSum) => {
        const numbers = [];
        // Iterate from 0 up to MAX_VAL
        for (let i = 0; i <= MAX_VAL; i++) {
            if (getDigitSum(i) === targetSum) {
                numbers.push(i);
            }
        }
        return numbers;
    };

    const n = digitSum.length;

    // Step 1: Precompute the set of valid numbers for each target digit sum
    // validNumbers[i] will be the sorted list of numbers <= 5000 with digit sum = i
    const validNumbers = new Map();
    for (let i = 0; i <= 50; i++) {
        validNumbers.set(i, findNumbersByDigitSum(i));
    }

    // DP state: dp[i][prev_val_index] = number of valid prefixes of length i+1
    // where the (i+1)-th element is the number corresponding to prev_val_index
    // This seems too complex due to the large number of possible values (up to 5001).

    // Alternative DP approach:
    // dp[i][j] = number of valid prefixes of length i such that the i-th element (arr[i-1]) is the j-th smallest number in validNumbers[digitSum[i-1]].
    // Since the number of valid numbers can be large, we need to refine the state.

    // The constraint is arr[i] >= arr[i-1].
    // Let's simplify the DP state based on the *value* of the last element.

    // dp[i][last_val] = number of valid arrays of length i ending with value last_val, where last_val has digit sum digitSum[i-1].
    // Since last_val can be up to 5000, this is feasible.

    // dp[i][v] = Number of ways to form a valid array of length i (indices 0 to i-1) such that arr[i-1] = v.

    // dp array: dp[i] will be a Map where keys are valid values for index i-1, and values are the counts.
    // dp[i]: Map<number, bigint>
    const dp = Array(n + 1).fill(0).map(() => new Map());

    // Base Case: i = 1 (processing digitSum[0])
    const targetSum0 = digitSum[0];
    const numbers0 = validNumbers.get(targetSum0) || [];
    if (numbers0.length > 0) {
        for (const num of numbers0) {
            dp[1].set(num, 1n);
        }
    }

    // Transitions: i = 2 to n (processing digitSum[i-1])
    for (let i = 2; i <= n; i++) {
        const currentTargetSum = digitSum[i - 1];
        const currentNumbers = validNumbers.get(currentTargetSum) || [];

        if (currentNumbers.length === 0) {
            // If there are no valid numbers for the current target sum, all subsequent counts will be 0.
            continue;
        }

        // Iterate over all possible values 'v_current' for arr[i-1]
        for (const v_current of currentNumbers) {
            let count = 0n;

            // Sum up counts from the previous state (i-1) where arr[i-2] <= v_current
            // Iterate over all possible previous values 'v_prev' that appeared in dp[i-1]
            for (const [v_prev, ways] of dp[i - 1].entries()) {
                if (v_prev <= v_current) {
                    count = (count + ways) % MOD;
                }
            }

            if (count > 0n) {
                dp[i].set(v_current, count);
            }
        }
    }

    // Final Result: Sum up all counts in dp[n]
    let totalCount = 0n;
    if (dp[n]) {
        for (const ways of dp[n].values()) {
            totalCount = (totalCount + ways) % MOD;
        }
    }

    return Number(totalCount);
}

