using namespace std;

typedef long long ll;

// Helper function to calculate the sum of digits
int getDigitSum(int n) {
    int sum = 0;
    string str = to_string(n);
    for (char c : str) {
        sum += c - '0';
    }
    return sum;
}

// Function to find all numbers <= MAX_VAL whose digit sum equals targetSum
vector<int> findNumbersByDigitSum(int targetSum, int maxVal) {
    vector<int> numbers;
    for (int i = 0; i <= maxVal; i++) {
        if (getDigitSum(i) == targetSum) {
            numbers.push_back(i);
        }
    }
    return numbers;
}

long long solve(std::vector<long long> digitSum) {
    const ll MOD = 1000000007;
    const int MAX_VAL = 5000;
    int n = digitSum.size();

    // Step 1: Precompute the set of valid numbers for each possible target digit sum (0 to 50)
    // validNumbers[i] will be the sorted list of numbers <= 5000 with digit sum = i
    // Since digitSum[i] <= 50, we only need up to 50.
    map<int, vector<int>> validNumbers;
    for (int i = 0; i <= 50; i++) {
        validNumbers[i] = findNumbersByDigitSum(i, MAX_VAL);
    }

    // DP state: dp[i] is a map where keys are valid values for arr[i-1], and values are the counts (modulo MOD).
    // dp[i]: Map<number, ll>
    // We use a vector of maps to represent the DP states for lengths 1 to n.
    vector<map<int, ll>> dp(n + 1);

    // Base Case: i = 1 (processing digitSum[0])
    int targetSum0 = (int)digitSum[0];
    if (validNumbers.count(targetSum0) && !validNumbers[targetSum0].empty()) {
        for (int num : validNumbers[targetSum0]) {
            dp[1][num] = 1;
        }
    }

    // Transitions: i = 2 to n (processing digitSum[i-1])
    for (int i = 2; i <= n; i++) {
        int currentTargetSum = (int)digitSum[i - 1];

        if (!validNumbers.count(currentTargetSum) || validNumbers[currentTargetSum].empty()) {
            // If there are no valid numbers for the current target sum, dp[i] will be empty.
            continue;
        }

        const vector<int>& currentNumbers = validNumbers[currentTargetSum];

        // Optimization: To efficiently calculate the sum of ways from dp[i-1] where v_prev <= v_current,
        // we can iterate over sorted values in dp[i-1].

        // Collect all (v_prev, ways) from dp[i-1] and sort them by v_prev
        vector<pair<int, ll>> prev_states;
        for (const auto& pair : dp[i - 1]) {
            prev_states.push_back(pair);
        }
        // Sorting is not strictly necessary if we use a prefix sum idea, 
        // but since the number of states might be up to 5001, iterating over all might be fine.
        // Let's stick to iterating over all previous states and using the condition v_prev <= v_current.

        // For better efficiency, we can pre-calculate prefix sums of ways based on value, but since we are mapping values, 
        // we just iterate through all previous states.

        // Iterate over all possible values 'v_current' for arr[i-1]
        for (int v_current : currentNumbers) {
            ll count = 0;

            // Sum up counts from the previous state (i-1) where arr[i-2] <= v_current
            for (const auto& pair : dp[i - 1]) {
                int v_prev = pair.first;
                ll ways = pair.second;

                if (v_prev <= v_current) {
                    count = (count + ways) % MOD;
                }
            }

            if (count > 0) {
                dp[i][v_current] = count;
            }
        }
    }

    // Final Result: Sum up all counts in dp[n]
    ll totalCount = 0;
    if (dp[n].empty() == false) {
        for (const auto& pair : dp[n]) {
            totalCount = (totalCount + pair.second) % MOD;
        }
    }

    return totalCount;
}
